def modify_user(self):
    cmd = []
    rc = None
    out = ''
    err = ''

    if self.password is not None and self.check_password():
        cmd = [self.module.get_bin_path('chpasswd', True)]
        if self.password_is_encrypted:
            cmd.append('-e')
        (rc, out, err) = self.execute_command(cmd, data="%s:%s\n" % (self.name, self.password))
        if rc != 0:
            self.module.fail_json(name=self.name, msg=err, rc=rc)

    if self.shell is not None and self.user_shell != self.shell:
        cmd = [self.module.get_bin_path('chsh', True), '-s', self.shell, self.name]
        (rc, out, err) = self.execute_command(cmd)
        if rc != 0:
            self.module.fail_json(name=self.name, msg=err, rc=rc)

    if self.groups is not None:
        current_groups = self.user_groups()
        groups_to_add = []
        groups_to_remove = []

        if self.append:
            for group in self.groups:
                if group not in current_groups:
                    groups_to_add.append(group)
        else:
            for group in self.groups:
                if group not in current_groups:
                    groups_to_add.append(group)
            for group in current_groups:
                if group not in self.groups and group != self.group:
                    groups_to_remove.append(group)

        for group in groups_to_add:
            cmd = [self.module.get_bin_path('addgroup', True), self.name, group]
            (rc, out, err) = self.execute_command(cmd)
            if rc != 0:
                self.module.fail_json(name=self.name, msg=err, rc=rc)

        for group in groups_to_remove:
            cmd = [self.module.get_bin_path('delgroup', True), self.name, group]
            (rc, out, err) = self.execute_command(cmd)
            if rc != 0:
                self.module.fail_json(name=self.name, msg=err, rc=rc)

    return (rc, out, err)

import numpy as np

cdef inline Py_hash_t safe_hash(object val) except? -1:
    if isinstance(val, np.datetime64):
        if val != val:  # NaT
            return hash(np.datetime64("NaT"))
        # Convert to a standard resolution (femtoseconds or attoseconds to avoid overflow, or just convert to a tuple of value and unit, or normalize to 'fs')
        # Actually, converting to 'fs' (femtoseconds) or 'as' (attoseconds) is safe from overflow for all reasonable datetime64 values.
        # Let's convert to 'as' (attoseconds) or 'ns' if possible, or simply use the timestamp/timedelta normalization.
        try:
            return hash(val.astype("M8[as]").view("i8"))
        except Exception:
            return hash(val.astype("M8[ns]").view("i8"))
    elif isinstance(val, np.timedelta64):
        if val != val:  # NaT
            return hash(np.timedelta64("NaT"))
        try:
            return hash(val.astype("m8[as]").view("i8"))
        except Exception:
            return hash(val.astype("m8[ns]").view("i8"))
    return hash(val)

