import numpy as np

cdef inline Py_hash_t safe_hash(object key) except? -1:
    if isinstance(key, (np.datetime64, np.timedelta64)):
        if np.isnat(key):
            return hash(np.datetime64("NaT"))
        # Convert to a stable representation (e.g. picoseconds or standard python objects)
        # to ensure x == y => hash(x) == hash(y)
        try:
            # Convert to standard python datetime/timedelta if possible
            return hash(key.tolist())
        except Exception:
